                          d='M20.8351 11.6662C21.1752 11.6662 21.4852 11.8762 21.6092 12.1942L23.8335 17.8348L29.4741 20.0591C29.6292 20.1208 29.7623 20.2276 29.8561 20.3658C29.9499 20.504 30 20.6671 30 20.8341C30 21.0011 29.9499 21.1643 29.8561 21.3025C29.7623 21.4407 29.6292 21.5475 29.4741 21.6092L23.8335 23.8335L21.6092 29.4741C21.5475 29.6292 21.4407 29.7623 21.3025 29.8561C21.1643 29.9499 21.0011 30 20.8341 30C20.6671 30 20.504 29.9499 20.3658 29.8561C20.2276 29.7623 20.1208 29.6292 20.0591 29.4741L17.8348 23.8335L12.1942 21.6092C12.039 21.5475 11.906 21.4407 11.8122 21.3025C11.7184 21.1643 11.6683 21.0011 11.6683 20.8341C11.6683 20.6671 11.7184 20.504 11.8122 20.3658C11.906 20.2276 12.039 20.1208 12.1942 20.0591L17.8348 17.8348L20.0591 12.1942C20.1212 12.039 20.2282 11.9058 20.3665 11.8117C20.5047 11.7176 20.6679 11.667 20.8351 11.6662ZM20.8351 14.7725L19.253 18.7809C19.2107 18.8871 19.1472 18.9836 19.0664 19.0644C18.9856 19.1452 18.8891 19.2087 18.7829 19.251L14.7725 20.8311L18.7829 22.4153C18.8889 22.4573 18.9853 22.5205 19.0661 22.601C19.1469 22.6814 19.2105 22.7775 19.253 22.8834L20.8331 26.8958L22.4173 22.8834C22.4596 22.7777 22.5228 22.6818 22.6033 22.6013C22.6838 22.5208 22.7797 22.4576 22.8854 22.4153L26.8978 20.8331L22.8854 19.251C22.7795 19.2085 22.6834 19.1449 22.603 19.0641C22.5225 18.9833 22.4593 18.8869 22.4173 18.7809L20.8351 14.7725ZM13.3344 10L14.3945 12.2722L16.6667 13.3324L14.3945 14.3945L13.3344 16.6667L12.2742 14.3945L10 13.3344L12.2722 12.2742L13.3344 10Z'
